import { useState, useMemo } from "react";
import { useLocation } from "wouter";
import { trpc } from "@/lib/trpc";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid,
  Tooltip, ResponsiveContainer, Cell,
} from "recharts";
import { Download, BarChart2, GitBranch, CheckCircle2 } from "lucide-react";

// --- helpers ---

function parseJsonArray(v: string | null | undefined): string[] {
  if (!v) return [];
  try { return JSON.parse(v); } catch { return []; }
}

function escapeCsvCell(v: string | number | null | undefined): string {
  if (v === null || v === undefined) return "";
  const s = String(v);
  if (s.includes(",") || s.includes('"') || s.includes("\n")) {
    return `"${s.replace(/"/g, '""')}"`;
  }
  return s;
}

function downloadCsv(filename: string, rows: (string | number)[][]): void {
  const csv = rows.map(r => r.map(escapeCsvCell).join(",")).join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

function pct(v: number | null | undefined): number {
  return Math.round((v ?? 0) * 100);
}

function avg(vals: number[]): number {
  if (!vals.length) return 0;
  return vals.reduce((a, b) => a + b, 0) / vals.length;
}

function toDate(v: unknown): Date {
  return new Date(v as number);
}

// --- sub-components ---

function ScoreBadge({ value }: { value: number }) {
  const color =
    value >= 70
      ? "bg-green-100 text-green-700"
      : value >= 40
        ? "bg-yellow-100 text-yellow-700"
        : "bg-red-100 text-red-700";
  return (
    <span className={`inline-block px-2 py-0.5 rounded text-xs font-semibold ${color}`}>
      {value}%
    </span>
  );
}

const CATEGORY_COLORS = ["#3b82f6", "#8b5cf6", "#14b8a6", "#f59e0b"];

function LineTooltip({ active, payload }: { active?: boolean; payload?: any[] }) {
  if (!active || !payload?.length) return null;
  const d = payload[0]?.payload;
  return (
    <div className="bg-white border rounded shadow-md p-2 text-xs max-w-48">
      <p className="font-semibold text-slate-800 truncate">{d?.jobTitle || "Untitled"}</p>
      <p className="text-slate-500">{d?.date}</p>
      <p className="text-blue-600 font-semibold">{d?.score}% match</p>
    </div>
  );
}

// --- main page ---

export default function Reports() {
  const [, navigate] = useLocation();
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [minScore, setMinScore] = useState(0);

  const { data: analyses = [], isLoading } = trpc.analysis.getPublicReport.useQuery();

  const filtered = useMemo(() => {
    return analyses.filter(a => {
      const date = toDate(a.createdAt);
      if (dateFrom && date < new Date(dateFrom)) return false;
      if (dateTo && date > new Date(dateTo + "T23:59:59")) return false;
      if (minScore > 0 && pct(a.matchScore) < minScore) return false;
      return true;
    });
  }, [analyses, dateFrom, dateTo, minScore]);

  const lineData = useMemo(
    () =>
      [...filtered]
        .sort((a, b) => (a.createdAt as number) - (b.createdAt as number))
        .map(a => ({
          date: toDate(a.createdAt).toLocaleDateString(),
          score: pct(a.matchScore),
          jobTitle: a.jobTitle ?? "Untitled",
        })),
    [filtered]
  );

  const avgData = useMemo(
    () => [
      { category: "Hard Skills", score: Math.round(avg(filtered.map(a => (a.hardSkillsScore ?? 0) * 100))), weight: "40%" },
      { category: "Experience", score: Math.round(avg(filtered.map(a => (a.experienceScore ?? 0) * 100))), weight: "30%" },
      { category: "Domain", score: Math.round(avg(filtered.map(a => (a.domainScore ?? 0) * 100))), weight: "20%" },
      { category: "Soft Skills", score: Math.round(avg(filtered.map(a => (a.softSkillsScore ?? 0) * 100))), weight: "10%" },
    ],
    [filtered]
  );

  const histData = useMemo(() => {
    const buckets = [
      { range: "0–19%", count: 0 },
      { range: "20–39%", count: 0 },
      { range: "40–59%", count: 0 },
      { range: "60–79%", count: 0 },
      { range: "80–100%", count: 0 },
    ];
    filtered.forEach(a => {
      const s = pct(a.matchScore);
      if (s < 20) buckets[0]!.count++;
      else if (s < 40) buckets[1]!.count++;
      else if (s < 60) buckets[2]!.count++;
      else if (s < 80) buckets[3]!.count++;
      else buckets[4]!.count++;
    });
    return buckets;
  }, [filtered]);

  const exportSummaryCsv = () => {
    const headers = ["Date", "Job Title", "Match %", "Hard Skills %", "Experience %", "Domain %", "Soft Skills %", "Mismatch %"];
    const rows = filtered.map(a => [
      toDate(a.createdAt).toLocaleDateString(),
      a.jobTitle ?? "",
      pct(a.matchScore),
      pct(a.hardSkillsScore),
      pct(a.experienceScore),
      pct(a.domainScore),
      pct(a.softSkillsScore),
      pct(a.mismatchScore),
    ]);
    downloadCsv("career-concierge-summary.csv", [headers, ...rows]);
  };

  const exportStrengthsGapsCsv = () => {
    const headers = ["Analysis ID", "Date", "Job Title", "Type", "Text"];
    const rows: (string | number)[][] = [];
    filtered.forEach(a => {
      const date = toDate(a.createdAt).toLocaleDateString();
      const title = a.jobTitle ?? "";
      parseJsonArray(a.topStrengths).forEach(s => rows.push([a.id, date, title, "Strength", s]));
      parseJsonArray(a.topGaps).forEach(g => rows.push([a.id, date, title, "Gap", g]));
    });
    downloadCsv("career-concierge-strengths-gaps.csv", [headers, ...rows]);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-indigo-50">
      <main className="container mx-auto px-4 py-12">

        {/* Header */}
        <div className="text-center max-w-3xl mx-auto mb-12">
          <h1 className="text-4xl font-bold text-slate-900 mb-4">Reporting & Analytics</h1>
          <p className="text-xl text-slate-600">
            Interactive job match analysis reporting with CSV export for Power BI integration.
          </p>
        </div>

        {/* Strategy Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-6xl mx-auto mb-12">

          {/* Why Recharts */}
          <Card className="hover:shadow-md hover:border-slate-300 transition-all">
            <CardHeader>
              <div className="flex items-center justify-between mb-2">
                <div className="w-10 h-10 bg-teal-100 rounded-lg flex items-center justify-center">
                  <BarChart2 className="h-5 w-5 text-teal-600" />
                </div>
                <Badge className="bg-teal-100 text-teal-700 border-0">Already Installed</Badge>
              </div>
              <CardTitle className="text-lg">In-App Recharts</CardTitle>
              <CardDescription>React-native interactive charts, zero extra dependencies</CardDescription>
            </CardHeader>
            <CardContent className="text-sm text-slate-600 space-y-2">
              <p>
                Recharts v2.15.2 is already bundled — no additional licenses, external services, or API
                keys required.
              </p>
              <p>
                Charts render directly from the same tRPC data the app already fetches. Filters update
                instantly in the browser with zero extra API calls.
              </p>
            </CardContent>
          </Card>

          {/* Options Evaluated */}
          <Card className="hover:shadow-md hover:border-slate-300 transition-all">
            <CardHeader>
              <div className="flex items-center justify-between mb-2">
                <div className="w-10 h-10 bg-slate-100 rounded-lg flex items-center justify-center">
                  <CheckCircle2 className="h-5 w-5 text-slate-600" />
                </div>
                <Badge variant="secondary">5 Options Evaluated</Badge>
              </div>
              <CardTitle className="text-lg">Options Evaluated</CardTitle>
              <CardDescription>Why Recharts was selected over BI platforms</CardDescription>
            </CardHeader>
            <CardContent>
              <table className="w-full text-xs">
                <thead>
                  <tr className="border-b">
                    <th className="text-left py-1 text-slate-500 font-medium">Option</th>
                    <th className="text-left py-1 text-slate-500 font-medium">Blocker</th>
                  </tr>
                </thead>
                <tbody className="text-slate-600">
                  <tr className="border-b">
                    <td className="py-1.5">Static Power BI PNG</td>
                    <td className="py-1.5">No interactivity</td>
                  </tr>
                  <tr className="border-b">
                    <td className="py-1.5">Power BI Embedded</td>
                    <td className="py-1.5">Azure AD + Pro license</td>
                  </tr>
                  <tr className="border-b">
                    <td className="py-1.5">Google Looker Studio</td>
                    <td className="py-1.5">External service</td>
                  </tr>
                  <tr className="border-b">
                    <td className="py-1.5">Tableau</td>
                    <td className="py-1.5">Paid license</td>
                  </tr>
                  <tr className="border-b">
                    <td className="py-1.5">D3.js</td>
                    <td className="py-1.5">High complexity</td>
                  </tr>
                  <tr className="bg-teal-50 rounded">
                    <td className="py-1.5 font-semibold text-teal-700">Recharts ✓</td>
                    <td className="py-1.5 text-teal-600">Already installed</td>
                  </tr>
                </tbody>
              </table>
            </CardContent>
          </Card>

          {/* Migration Path */}
          <Card className="hover:shadow-md hover:border-slate-300 transition-all">
            <CardHeader>
              <div className="flex items-center justify-between mb-2">
                <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                  <GitBranch className="h-5 w-5 text-blue-600" />
                </div>
                <Badge className="bg-blue-100 text-blue-700 border-0">Export Ready</Badge>
              </div>
              <CardTitle className="text-lg">Migration Path to Power BI</CardTitle>
              <CardDescription>CSV exports → Power BI Desktop → Service</CardDescription>
            </CardHeader>
            <CardContent className="text-sm text-slate-600 space-y-2">
              <p>
                The two CSV exports below share an{" "}
                <code className="bg-slate-100 px-1 rounded text-xs">analysisId</code> key, forming a
                1:many relational model that maps directly to Power BI tables.
              </p>
              <p>
                Migration: export both CSVs → open Power BI Desktop → load both tables → set
                relationship on <code className="bg-slate-100 px-1 rounded text-xs">analysisId</code>{" "}
                → build reports → publish to Power BI Service.
              </p>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <Card className="max-w-6xl mx-auto mb-8">
          <CardHeader>
            <CardTitle>Filters</CardTitle>
            <CardDescription>Narrow the dataset — charts and table update instantly</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="flex flex-wrap gap-6 items-end">
              <div>
                <Label htmlFor="dateFrom">Date From</Label>
                <Input
                  id="dateFrom"
                  type="date"
                  value={dateFrom}
                  onChange={e => setDateFrom(e.target.value)}
                  className="w-40"
                />
              </div>
              <div>
                <Label htmlFor="dateTo">Date To</Label>
                <Input
                  id="dateTo"
                  type="date"
                  value={dateTo}
                  onChange={e => setDateTo(e.target.value)}
                  className="w-40"
                />
              </div>
              <div>
                <Label htmlFor="minScore">Min Match Score (%)</Label>
                <Input
                  id="minScore"
                  type="number"
                  min={0}
                  max={100}
                  value={minScore || ""}
                  placeholder="0"
                  onChange={e => setMinScore(Number(e.target.value))}
                  className="w-28"
                />
              </div>
              <Button
                variant="outline"
                onClick={() => { setDateFrom(""); setDateTo(""); setMinScore(0); }}
              >
                Reset
              </Button>
              <span className="text-sm text-slate-500 ml-auto self-end">
                {filtered.length} of {analyses.length} analyses shown
              </span>
            </div>
          </CardContent>
        </Card>

        {isLoading ? (
          <div className="text-center text-slate-500 py-16">Loading analysis data…</div>
        ) : analyses.length === 0 ? (
          <div className="text-center text-slate-500 py-16">
            No analyses yet. Analyze a job description on the{" "}
            <a href="/match" className="text-blue-600 hover:underline">Match</a> page first.
          </div>
        ) : (
          <>
            {/* Charts row */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 max-w-6xl mx-auto mb-6">

              {/* Line: Scores Over Time */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Match Score Over Time</CardTitle>
                  <CardDescription>Overall match % per analysis, chronologically</CardDescription>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={240}>
                    <LineChart data={lineData} margin={{ top: 4, right: 16, bottom: 4, left: -10 }}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                      <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                      <YAxis domain={[0, 100]} tick={{ fontSize: 11 }} unit="%" />
                      <Tooltip content={<LineTooltip />} />
                      <Line
                        type="monotone"
                        dataKey="score"
                        stroke="#3b82f6"
                        strokeWidth={2}
                        dot={{ r: 4 }}
                        activeDot={{ r: 6 }}
                      />
                    </LineChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>

              {/* Bar: Average Category Scores */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Average Category Scores</CardTitle>
                  <CardDescription>Mean score per pillar across filtered analyses</CardDescription>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={240}>
                    <BarChart data={avgData} margin={{ top: 4, right: 16, bottom: 4, left: -10 }}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                      <XAxis dataKey="category" tick={{ fontSize: 11 }} />
                      <YAxis domain={[0, 100]} tick={{ fontSize: 11 }} unit="%" />
                      <Tooltip formatter={(v: number) => [`${v}%`, "Avg Score"]} />
                      <Bar dataKey="score" radius={[4, 4, 0, 0]}>
                        {avgData.map((_, i) => (
                          <Cell key={i} fill={CATEGORY_COLORS[i]} />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>
            </div>

            {/* Histogram */}
            <Card className="max-w-6xl mx-auto mb-8">
              <CardHeader>
                <CardTitle className="text-base">Score Distribution</CardTitle>
                <CardDescription>Number of analyses in each match score tier</CardDescription>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={histData} margin={{ top: 4, right: 16, bottom: 4, left: -10 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                    <XAxis dataKey="range" tick={{ fontSize: 12 }} />
                    <YAxis allowDecimals={false} tick={{ fontSize: 11 }} />
                    <Tooltip formatter={(v: number) => [v, "Analyses"]} />
                    <Bar dataKey="count" fill="#6366f1" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            {/* Table + CSV Export */}
            <Card className="max-w-6xl mx-auto">
              <CardHeader>
                <div className="flex items-center justify-between flex-wrap gap-3">
                  <div>
                    <CardTitle className="text-base">Analysis Data Table</CardTitle>
                    <CardDescription>Click any row to view the full report</CardDescription>
                  </div>
