                    <Button variant="outline" size="sm" onClick={exportStrengthsGapsCsv}>
                      <Download className="h-4 w-4 mr-1" />
                      Strengths &amp; Gaps CSV
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b text-left">
                        <th className="pb-2 pr-4 text-slate-500 font-medium whitespace-nowrap">Date</th>
                        <th className="pb-2 pr-4 text-slate-500 font-medium">Job Title</th>
                        <th className="pb-2 pr-4 text-slate-500 font-medium whitespace-nowrap">Match</th>
                        <th className="pb-2 pr-4 text-slate-500 font-medium whitespace-nowrap">Hard Skills</th>
                        <th className="pb-2 pr-4 text-slate-500 font-medium whitespace-nowrap">Experience</th>
                        <th className="pb-2 pr-4 text-slate-500 font-medium whitespace-nowrap">Domain</th>
                        <th className="pb-2 text-slate-500 font-medium whitespace-nowrap">Soft Skills</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filtered.map(a => (
                        <tr
                          key={a.id}
                          onClick={() => navigate(`/analysis/${a.id}`)}
